// Format VectorStore results as observation string.
// Re-attach original ReAct Loop data (agentState, thought, action, actionInput)
// because VectorStore Query overwrites the item with its own output.
const reactData = $('ReAct Loop').item.json;
const results = $input.item.json.results ?? [];
const observation = JSON.stringify({
  documents: results.map(r => ({
    id: r.id,
    text: r.document,
    relevance: r.distance
  }))
});
return [{ json: { ...reactData, observation } }];

const state = $input.item.json;
const finalAnswer = state.finalAnswer ?? '';
const success = finalAnswer.includes('2.4') || finalAnswer.toLowerCase().includes('software');
console.log('=== SC-02 BENCHMARK RESULT ===');
console.log('Final Answer:', finalAnswer);
console.log('Step Count:', state.stepCount);
console.log('Success:', success);
return [{ json: { finalAnswer, stepCount: state.stepCount, success, reminder: 'Fill in evaluation/results/SC-02_artefact_run001.json' } }];
